#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10,M=N*43,INF=1e8;

int n,m,k,S,T,h[25],r[25],s[25][20],f[20];
int head[N],ver[M],edge[M],nxt[M],tot=1;
int d[N],now[N];

int father(int x){
    return f[x]==x?x:f[x]=father(f[x]);
}

void merge(int x,int y){
    int fx=father(x),fy=father(y);
    if(fx!=fy)
        f[fy]=fx;
}

void add(int u,int v,int w){
    ver[++tot]=v,edge[tot]=w,nxt[tot]=head[u],head[u]=tot;
    ver[++tot]=u,edge[tot]=0,nxt[tot]=head[v],head[v]=tot;
}

bool bfs(){
    memset(d,0,sizeof(d));
    queue<int> q;
    q.push(S),d[S]=1,now[S]=head[S];
    while(q.size()){
        int x=q.front();
        q.pop();
        for(int i=head[x],y;i;i=nxt[i])
            if(!d[y=ver[i]] && edge[i]){
                d[y]=d[x]+1,now[y]=head[y];
                if(y==T)
                    return 1;
                q.push(y);
            }
    }
    return 0;
}

int Dinic(int x,int flow){
    if(x==T)
        return flow;
    int res=0;
    for(int i=now[x],y;i && res<flow;i=nxt[i]){
        y=ver[i],now[x]=i;
        if(d[y]==d[x]+1 && edge[i]){
            int tmp=Dinic(y,min(edge[i],flow-res));
            if(!tmp)
                d[y]=0;
            edge[i]-=tmp,edge[i^1]+=tmp;
            res+=tmp;
        }
    }
    return res;
}

int main(){
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=n+2;i++)
		f[i]=i; 
	for(int i=1;i<=m;i++){
        scanf("%d%d",&h[i],&r[i]);
        for(int j=0;j<r[i];j++){
            scanf("%d",&s[i][j]);
            s[i][j]+=2;
            if(j)
                merge(s[i][j],s[i][j-1]);
        }
    }
    if(father(1)!=father(2)){
        printf("0");
        return 0;
    }
    n+=2;
    S=0,T=(n+1)*n*n*k+1;
    add(S,2,k);
    add(1,T,INF);
    int flow,max_flow=0;
    for(int res=1;;res++){
        for(int i=1;i<=m;i++)
            add((res-1)*n+s[i][(res-1)%r[i]],res*n+s[i][res%r[i]],h[i]);
        for(int i=1;i<=n;i++)
            add((res-1)*n+i,res*n+i,INF);
        add(res*n+1,T,INF);
        while(bfs())
            while(flow=Dinic(S,INF))
                max_flow+=flow;
        if(max_flow==k){
            printf("%d",res);
            break;
        }
    }
    return 0;
}
